"""
LanguageCollaborator - A collaborative language learning application.

Facilitates collaborative learning among multiple users by providing
interactive language exercises, real-time feedback, and peer review capabilities.
"""

import hashlib
import uuid
import threading
import time
import re
from datetime import datetime
from typing import Dict, List, Optional, Any


# ---------------------------------------------------------------------------
# Security & Authentication
# ---------------------------------------------------------------------------

class AuthManager:
    """Handles user authentication and session management."""

    def __init__(self):
        self._users: Dict[str, dict] = {}
        self._sessions: Dict[str, str] = {}
        self._lock = threading.Lock()

    def _hash_password(self, password: str) -> str:
        return hashlib.sha256(password.encode()).hexdigest()

    def register(self, username: str, password: str) -> dict:
        with self._lock:
            if not username or not password:
                return {"success": False, "error": "Username and password required"}
            if len(password) < 6:
                return {"success": False, "error": "Password must be at least 6 characters"}
            if username in self._users:
                return {"success": False, "error": "Username already exists"}
            self._users[username] = {
                "username": username,
                "password_hash": self._hash_password(password),
                "created_at": datetime.now().isoformat(),
            }
            return {"success": True, "message": f"User '{username}' registered"}

    def login(self, username: str, password: str) -> dict:
        with self._lock:
            if username not in self._users:
                return {"success": False, "error": "Invalid credentials"}
            if self._users[username]["password_hash"] != self._hash_password(password):
                return {"success": False, "error": "Invalid credentials"}
            token = str(uuid.uuid4())
            self._sessions[token] = username
            return {"success": True, "token": token, "username": username}

    def logout(self, token: str) -> dict:
        with self._lock:
            if token in self._sessions:
                del self._sessions[token]
                return {"success": True, "message": "Logged out"}
            return {"success": False, "error": "Invalid session"}

    def validate_session(self, token: str) -> Optional[str]:
        with self._lock:
            return self._sessions.get(token)

    def get_user_count(self) -> int:
        with self._lock:
            return len(self._users)


# ---------------------------------------------------------------------------
# Exercise Models
# ---------------------------------------------------------------------------

class Exercise:
    """Base class for all language exercises."""

    def __init__(self, creator: str, title: str, description: str, exercise_type: str):
        self.id = str(uuid.uuid4())
        self.creator = creator
        self.title = title
        self.description = description
        self.exercise_type = exercise_type
        self.created_at = datetime.now().isoformat()
        self.shared_with: List[str] = []
        self.is_public = False
        self.reviews: List[dict] = []

    def to_dict(self) -> dict:
        return {
            "id": self.id,
            "creator": self.creator,
            "title": self.title,
            "description": self.description,
            "exercise_type": self.exercise_type,
            "created_at": self.created_at,
            "shared_with": self.shared_with,
            "is_public": self.is_public,
            "reviews": self.reviews,
        }


class GrammarQuiz(Exercise):
    """Grammar quiz with multiple choice questions."""

    def __init__(self, creator: str, title: str, description: str, questions: List[dict]):
        super().__init__(creator, title, description, "grammar_quiz")
        self.questions = questions  # [{"question": str, "options": list, "correct": int}]

    def check_answers(self, answers: List[int]) -> dict:
        if len(answers) != len(self.questions):
            return {
                "success": False,
                "error": f"Expected {len(self.questions)} answers, got {len(answers)}",
            }
        results = []
        correct_count = 0
        for i, (question, answer) in enumerate(zip(self.questions, answers)):
            is_correct = answer == question["correct"]
            if is_correct:
                correct_count += 1
            results.append({
                "question_index": i,
                "question": question["question"],
                "your_answer": answer,
                "correct_answer": question["correct"],
                "is_correct": is_correct,
            })
        score = correct_count / len(self.questions) * 100 if self.questions else 0
        return {
            "success": True,
            "score": score,
            "correct": correct_count,
            "total": len(self.questions),
            "results": results,
            "feedback": self._generate_feedback(score),
        }

    def _generate_feedback(self, score: float) -> str:
        if score == 100:
            return "Perfect score! Excellent grammar knowledge!"
        elif score >= 80:
            return "Great job! You have a strong grasp of grammar."
        elif score >= 60:
            return "Good effort! Review the incorrect answers to improve."
        elif score >= 40:
            return "Keep practicing! Focus on the grammar rules you missed."
        else:
            return "Don't give up! Consider reviewing basic grammar concepts."


class VocabularyTest(Exercise):
    """Vocabulary matching test."""

    def __init__(self, creator: str, title: str, description: str, word_pairs: List[dict]):
        super().__init__(creator, title, description, "vocabulary_test")
        self.word_pairs = word_pairs  # [{"word": str, "definition": str}]

    def check_answers(self, answers: Dict[str, str]) -> dict:
        results = []
        correct_count = 0
        for pair in self.word_pairs:
            word = pair["word"]
            expected = pair["definition"].lower().strip()
            given = answers.get(word, "").lower().strip()
            is_correct = given == expected
            if is_correct:
                correct_count += 1
            results.append({
                "word": word,
                "your_answer": answers.get(word, ""),
                "correct_answer": pair["definition"],
                "is_correct": is_correct,
            })
        total = len(self.word_pairs)
        score = correct_count / total * 100 if total else 0
        return {
            "success": True,
            "score": score,
            "correct": correct_count,
            "total": total,
            "results": results,
            "feedback": self._generate_feedback(score),
        }

    def _generate_feedback(self, score: float) -> str:
        if score == 100:
            return "Outstanding vocabulary knowledge!"
        elif score >= 80:
            return "Impressive! Your vocabulary is strong."
        elif score >= 60:
            return "Good progress! Keep expanding your vocabulary."
        elif score >= 40:
            return "Practice makes perfect! Try flashcards for tricky words."
        else:
            return "Keep at it! Regular reading helps build vocabulary."


class WritingPrompt(Exercise):
    """Writing exercise with automated feedback."""

    COMMON_GRAMMAR_ERRORS = {
        r"\bi\b(?!['']\w)": "Capitalize 'I' when used as a pronoun.",
        r"\s{2,}": "Avoid multiple consecutive spaces.",
        r"[.!?]\s*[a-z]": "Capitalize the first letter after sentence-ending punctuation.",
    }

    WEAK_WORDS = ["very", "really", "just", "thing", "stuff", "got", "nice", "good", "bad"]

    def __init__(self, creator: str, title: str, description: str,
                 prompt_text: str, min_words: int = 50, max_words: int = 500):
        super().__init__(creator, title, description, "writing_prompt")
        self.prompt_text = prompt_text
        self.min_words = min_words
        self.max_words = max_words
        self.submissions: Dict[str, dict] = {}

    def submit_response(self, username: str, text: str) -> dict:
        if not text or not text.strip():
            return {"success": False, "error": "Response text cannot be empty"}

        word_count = len(text.split())
        feedback = self._analyze_writing(text, word_count)

        submission = {
            "username": username,
            "text": text,
            "word_count": word_count,
            "submitted_at": datetime.now().isoformat(),
            "feedback": feedback,
        }
        self.submissions[username] = submission
        return {"success": True, "submission": submission}

    def _analyze_writing(self, text: str, word_count: int) -> dict:
        suggestions = []
        grammar_issues = []
        vocabulary_suggestions = []

        # Word count check
        if word_count < self.min_words:
            suggestions.append(
                f"Your response has {word_count} words. "
                f"Try to write at least {self.min_words} words for a complete answer."
            )
        elif word_count > self.max_words:
            suggestions.append(
                f"Your response has {word_count} words. "
                f"Consider being more concise (max {self.max_words} words)."
            )

        # Grammar checks
        for pattern, message in self.COMMON_GRAMMAR_ERRORS.items():
            if re.search(pattern, text):
                grammar_issues.append(message)

        # Vocabulary suggestions
        text_lower = text.lower()
        for word in self.WEAK_WORDS:
            if f" {word} " in f" {text_lower} ":
                vocabulary_suggestions.append(
                    f"Consider replacing '{word}' with a more specific word."
                )

        # Sentence variety
        sentences = re.split(r"[.!?]+", text)
        sentences = [s.strip() for s in sentences if s.strip()]
        if len(sentences) >= 3:
            lengths = [len(s.split()) for s in sentences]
            avg_len = sum(lengths) / len(lengths)
            variance = sum((l - avg_len) ** 2 for l in lengths) / len(lengths)
            if variance < 4:
                suggestions.append(
                    "Try varying your sentence lengths for more engaging writing."
                )

        score = self._calculate_writing_score(
            word_count, grammar_issues, vocabulary_suggestions, sentences
        )

        return {
            "score": score,
            "word_count": word_count,
            "sentence_count": len(sentences),
            "grammar_issues": grammar_issues,
            "vocabulary_suggestions": vocabulary_suggestions,
            "general_suggestions": suggestions,
            "overall_feedback": self._overall_writing_feedback(score),
        }

    def _calculate_writing_score(self, word_count: int, grammar_issues: list,
                                  vocab_suggestions: list, sentences: list) -> float:
        score = 100.0
        # Deductions for grammar issues
        score -= len(grammar_issues) * 5
        # Deductions for weak vocabulary
        score -= len(vocab_suggestions) * 3
        # Word count penalties
        if word_count < self.min_words:
            score -= 10
        elif word_count > self.max_words:
            score -= 5
        # Bonus for sentence variety
        if len(sentences) >= 5:
            score += 5
        return max(0, min(100, score))

    def _overall_writing_feedback(self, score: float) -> str:
        if score >= 90:
            return "Excellent writing! Clear, well-structured, and engaging."
        elif score >= 75:
            return "Good writing! Minor improvements could make it even better."
        elif score >= 60:
            return "Decent effort. Focus on grammar and word choice."
        elif score >= 40:
            return "Needs improvement. Review grammar rules and expand vocabulary."
        else:
            return "Keep practicing! Consider reviewing writing fundamentals."


