class PeerReviewSystem:
    """Manages peer reviews between users."""

    def __init__(self):
        self._reviews: Dict[str, List[dict]] = {}  # exercise_id -> reviews
        self._lock = threading.Lock()

    def submit_review(self, exercise_id: str, reviewer: str, creator: str,
                      rating: int, comment: str) -> dict:
        if reviewer == creator:
            return {"success": False, "error": "Cannot review your own exercise"}
        if not 1 <= rating <= 5:
            return {"success": False, "error": "Rating must be between 1 and 5"}
        if not comment or len(comment.strip()) < 10:
            return {"success": False, "error": "Review comment must be at least 10 characters"}

        review = {
            "id": str(uuid.uuid4()),
            "exercise_id": exercise_id,
            "reviewer": reviewer,
            "rating": rating,
            "comment": comment,
            "created_at": datetime.now().isoformat(),
        }

        with self._lock:
            if exercise_id not in self._reviews:
                self._reviews[exercise_id] = []
            # Check for duplicate review
            for existing in self._reviews[exercise_id]:
                if existing["reviewer"] == reviewer:
                    return {"success": False, "error": "You already reviewed this exercise"}
            self._reviews[exercise_id].append(review)

        return {"success": True, "review": review}

    def get_reviews(self, exercise_id: str) -> List[dict]:
        with self._lock:
            return self._reviews.get(exercise_id, [])

    def get_average_rating(self, exercise_id: str) -> Optional[float]:
        with self._lock:
            reviews = self._reviews.get(exercise_id, [])
            if not reviews:
                return None
            return sum(r["rating"] for r in reviews) / len(reviews)


# ---------------------------------------------------------------------------
# Exercise Manager
# ---------------------------------------------------------------------------

class ExerciseManager:
    """Manages exercise creation, sharing, and retrieval."""

    def __init__(self):
        self._exercises: Dict[str, Exercise] = {}
        self._lock = threading.Lock()

    def create_grammar_quiz(self, creator: str, title: str, description: str,
                            questions: List[dict]) -> dict:
        if not title or not description:
            return {"success": False, "error": "Title and description required"}
        if not questions:
            return {"success": False, "error": "At least one question required"}
        for i, q in enumerate(questions):
            if "question" not in q or "options" not in q or "correct" not in q:
                return {"success": False, "error": f"Question {i} missing required fields"}
            if not isinstance(q["options"], list) or len(q["options"]) < 2:
                return {"success": False, "error": f"Question {i} needs at least 2 options"}
            if not isinstance(q["correct"], int) or q["correct"] < 0 or q["correct"] >= len(q["options"]):
                return {"success": False, "error": f"Question {i} has invalid correct answer index"}

        exercise = GrammarQuiz(creator, title, description, questions)
        with self._lock:
            self._exercises[exercise.id] = exercise
        return {"success": True, "exercise_id": exercise.id, "exercise": exercise.to_dict()}

    def create_vocabulary_test(self, creator: str, title: str, description: str,
                               word_pairs: List[dict]) -> dict:
        if not title or not description:
            return {"success": False, "error": "Title and description required"}
        if not word_pairs:
            return {"success": False, "error": "At least one word pair required"}
        for i, wp in enumerate(word_pairs):
            if "word" not in wp or "definition" not in wp:
                return {"success": False, "error": f"Word pair {i} missing required fields"}

        exercise = VocabularyTest(creator, title, description, word_pairs)
        with self._lock:
            self._exercises[exercise.id] = exercise
        return {"success": True, "exercise_id": exercise.id, "exercise": exercise.to_dict()}

    def create_writing_prompt(self, creator: str, title: str, description: str,
                              prompt_text: str, min_words: int = 50,
                              max_words: int = 500) -> dict:
        if not title or not description:
            return {"success": False, "error": "Title and description required"}
        if not prompt_text:
            return {"success": False, "error": "Prompt text required"}

        exercise = WritingPrompt(creator, title, description, prompt_text, min_words, max_words)
        with self._lock:
            self._exercises[exercise.id] = exercise
        return {"success": True, "exercise_id": exercise.id, "exercise": exercise.to_dict()}

    def share_exercise(self, exercise_id: str, owner: str, target_user: str) -> dict:
        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return {"success": False, "error": "Exercise not found"}
            if exercise.creator != owner:
                return {"success": False, "error": "Only the creator can share this exercise"}
            if target_user in exercise.shared_with:
                return {"success": False, "error": f"Already shared with '{target_user}'"}
            exercise.shared_with.append(target_user)
        return {"success": True, "message": f"Exercise shared with '{target_user}'"}

    def make_public(self, exercise_id: str, owner: str) -> dict:
        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return {"success": False, "error": "Exercise not found"}
            if exercise.creator != owner:
                return {"success": False, "error": "Only the creator can make this public"}
            exercise.is_public = True
        return {"success": True, "message": "Exercise is now public"}

    def get_exercise(self, exercise_id: str, username: str) -> dict:
        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return {"success": False, "error": "Exercise not found"}
            if not self._has_access(exercise, username):
                return {"success": False, "error": "Access denied"}
            return {"success": True, "exercise": exercise.to_dict()}

    def get_user_exercises(self, username: str) -> List[dict]:
        with self._lock:
            results = []
            for exercise in self._exercises.values():
                if exercise.creator == username:
                    results.append(exercise.to_dict())
            return results

    def get_available_exercises(self, username: str) -> List[dict]:
        with self._lock:
            results = []
            for exercise in self._exercises.values():
                if self._has_access(exercise, username):
                    results.append(exercise.to_dict())
            return results

    def attempt_exercise(self, exercise_id: str, username: str, answers: Any) -> dict:
        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return {"success": False, "error": "Exercise not found"}
            if not self._has_access(exercise, username):
                return {"success": False, "error": "Access denied"}

        if isinstance(exercise, GrammarQuiz):
            if not isinstance(answers, list):
                return {"success": False, "error": "Answers must be a list of indices"}
            return exercise.check_answers(answers)
        elif isinstance(exercise, VocabularyTest):
            if not isinstance(answers, dict):
                return {"success": False, "error": "Answers must be a dict of word: definition"}
            return exercise.check_answers(answers)
        elif isinstance(exercise, WritingPrompt):
            if not isinstance(answers, str):
                return {"success": False, "error": "Answer must be a text string"}
            return exercise.submit_response(username, answers)
        return {"success": False, "error": "Unknown exercise type"}

    def get_exercise_obj(self, exercise_id: str) -> Optional[Exercise]:
        with self._lock:
            return self._exercises.get(exercise_id)

    def _has_access(self, exercise: Exercise, username: str) -> bool:
        if exercise.creator == username:
            return True
        if exercise.is_public:
            return True
        if username in exercise.shared_with:
            return True
        return False


