class LanguageCollaborator:
    """
    Main application class that orchestrates the collaborative language
    learning platform.
    """

    def __init__(self):
        self.auth = AuthManager()
        self.exercises = ExerciseManager()
        self.peer_reviews = PeerReviewSystem()
        self._lock = threading.Lock()

    # --- Auth endpoints ---

    def register_user(self, username: str, password: str) -> dict:
        return self.auth.register(username, password)

    def login_user(self, username: str, password: str) -> dict:
        return self.auth.login(username, password)

    def logout_user(self, token: str) -> dict:
        return self.auth.logout(token)

    # --- Exercise endpoints ---

    def create_exercise(self, token: str, exercise_type: str, **kwargs) -> dict:
        username = self.auth.validate_session(token)
        if not username:
            return {"success": False, "error": "Authentication required"}

        if exercise_type == "grammar_quiz":
            return self.exercises.create_grammar_quiz(
                creator=username,
                title=kwargs.get("title", ""),
                description=kwargs.get("description", ""),
                questions=kwargs.get("questions", []),
            )
        elif exercise_type == "vocabulary_test":
            return self.exercises.create_vocabulary_test(
                creator=username,
                title=kwargs.get("title", ""),
                description=kwargs.get("description", ""),
                word_pairs=kwargs.get("word_pairs", []),
            )
        elif exercise_type == "writing_prompt":
            return self.exercises.create_writing_prompt(
                creator=username,
                title=kwargs.get("title", ""),
                description=kwargs.get("description", ""),
                prompt_text=kwargs.get("prompt_text", ""),
                min_words=kwargs.get("min_words", 50),
                max_words=kwargs.get("max_words", 500),
            )
        return {"success": False, "error": f"Unknown exercise type: {exercise_type}"}

    def share_exercise(self, token: str, exercise_id: str, target_user: str) -> dict:
        username = self.auth.validate_session(token)
        if not username:
            return {"success": False, "error": "Authentication required"}
        return self.exercises.share_exercise(exercise_id, username, target_user)

    def make_exercise_public(self, token: str, exercise_id: str) -> dict:
        username = self.auth.validate_session(token)
        if not username:
            return {"success": False, "error": "Authentication required"}
        return self.exercises.make_public(exercise_id, username)

    def get_exercise(self, token: str, exercise_id: str) -> dict:
        username = self.auth.validate_session(token)
        if not username:
            return {"success": False, "error": "Authentication required"}
        return self.exercises.get_exercise(exercise_id, username)

    def get_my_exercises(self, token: str) -> dict:
        username = self.auth.validate_session(token)
        if not username:
            return {"success": False, "error": "Authentication required"}
        return {"success": True, "exercises": self.exercises.get_user_exercises(username)}

    def get_available_exercises(self, token: str) -> dict:
        username = self.auth.validate_session(token)
        if not username:
            return {"success": False, "error": "Authentication required"}
        return {"success": True, "exercises": self.exercises.get_available_exercises(username)}

    def attempt_exercise(self, token: str, exercise_id: str, answers: Any) -> dict:
        username = self.auth.validate_session(token)
        if not username:
            return {"success": False, "error": "Authentication required"}
        return self.exercises.attempt_exercise(exercise_id, username, answers)

    # --- Peer review endpoints ---

    def submit_review(self, token: str, exercise_id: str, rating: int, comment: str) -> dict:
        username = self.auth.validate_session(token)
        if not username:
            return {"success": False, "error": "Authentication required"}

        exercise = self.exercises.get_exercise_obj(exercise_id)
        if not exercise:
            return {"success": False, "error": "Exercise not found"}

        # Verify reviewer has access to the exercise
        access_check = self.exercises.get_exercise(exercise_id, username)
        if not access_check.get("success"):
            return {"success": False, "error": "Access denied"}

        return self.peer_reviews.submit_review(
            exercise_id, username, exercise.creator, rating, comment
        )

    def get_reviews(self, token: str, exercise_id: str) -> dict:
        username = self.auth.validate_session(token)
        if not username:
            return {"success": False, "error": "Authentication required"}

        access_check = self.exercises.get_exercise(exercise_id, username)
        if not access_check.get("success"):
            return {"success": False, "error": "Access denied"}

        reviews = self.peer_reviews.get_reviews(exercise_id)
        avg_rating = self.peer_reviews.get_average_rating(exercise_id)
        return {
            "success": True,
            "reviews": reviews,
            "average_rating": avg_rating,
            "review_count": len(reviews),
        }


