def run_tests():
    """Comprehensive test suite for LanguageCollaborator."""
    passed = 0
    failed = 0
    errors = []

    def assert_true(condition, test_name):
        nonlocal passed, failed
        if condition:
            passed += 1
        else:
            failed += 1
            errors.append(f"FAILED: {test_name}")

    def assert_equal(actual, expected, test_name):
        nonlocal passed, failed
        if actual == expected:
            passed += 1
        else:
            failed += 1
            errors.append(f"FAILED: {test_name} (expected={expected}, got={actual})")

    # --- Test: User Registration and Login ---
    print("=" * 60)
    print("TEST SUITE: LanguageCollaborator")
    print("=" * 60)

    app = LanguageCollaborator()

    print("\n--- Test: User Registration ---")
    result = app.register_user("alice", "password123")
    assert_true(result["success"], "Register alice")

    result = app.register_user("bob", "secure456")
    assert_true(result["success"], "Register bob")

    result = app.register_user("charlie", "mypass789")
    assert_true(result["success"], "Register charlie")

    # Duplicate registration
    result = app.register_user("alice", "different")
    assert_true(not result["success"], "Duplicate registration rejected")
    assert_equal(result["error"], "Username already exists", "Duplicate error message")

    # Invalid registration
    result = app.register_user("", "password")
    assert_true(not result["success"], "Empty username rejected")

    result = app.register_user("dave", "short")
    assert_true(not result["success"], "Short password rejected")

    print("\n--- Test: User Login ---")
    login_alice = app.login_user("alice", "password123")
    assert_true(login_alice["success"], "Alice login")
    token_alice = login_alice["token"]

    login_bob = app.login_user("bob", "secure456")
    assert_true(login_bob["success"], "Bob login")
    token_bob = login_bob["token"]

    login_charlie = app.login_user("charlie", "mypass789")
    assert_true(login_charlie["success"], "Charlie login")
    token_charlie = login_charlie["token"]

    # Invalid login
    result = app.login_user("alice", "wrongpassword")
    assert_true(not result["success"], "Wrong password rejected")

    result = app.login_user("nonexistent", "password")
    assert_true(not result["success"], "Nonexistent user rejected")

    # --- Test: Grammar Quiz Creation and Attempt ---
    print("\n--- Test: Grammar Quiz ---")
